const Tesseract4D = () => {
  const [r, setR] = React.useState({ x: 0, y: 0, z: 0 });
  React.useEffect(() => {
    let id,
      f = 0;
    const tick = () => {
      f++;
      setR({ x: f * 0.5, y: f * 0.3, z: f * 0.15 });
      id = requestAnimationFrame(tick);
    };
    id = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(id);
  }, []);
  const o = {
    transform:
      "rotateX(" + r.x + "deg) rotateY(" + r.y + "deg) rotateZ(" + r.z + "deg)",
    transformStyle: "preserve-3d",
    position: "absolute",
    inset: 0,
  };
  const i = {
    transform:
      "rotateX(" +
      -r.x * 0.6 +
      "deg) rotateY(" +
      -r.y * 0.4 +
      "deg) rotateZ(" +
      r.z * 1.5 +
      "deg)",
    transformStyle: "preserve-3d",
    position: "absolute",
    top: 25,
    left: 25,
    right: 25,
    bottom: 25,
  };
  const F = ({ t, bg, bc, w, h, l, tp }) => (
    <div
      style={{
        position: "absolute",
        width: w || 110,
        height: h || 110,
        left: l || 0,
        top: tp || 0,
        background: bg,
        border: "1.5px solid " + bc,
        transform: t,
      }}
    />
  );
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        minHeight: "100vh",
        background: "#030712",
        perspective: "700px",
      }}
    >
      <div
        style={{
          position: "relative",
          width: 110,
          height: 110,
          transformStyle: "preserve-3d",
          margin: "0 auto",
        }}
      >
        <div style={o}>
          {[
            [
              "rotateX(90deg) translateZ(55px)",
              "rgba(99,102,241,.15)",
              "#6366f1",
            ],
            [
              "rotateX(-90deg) translateZ(55px)",
              "rgba(139,92,246,.15)",
              "#8b5cf6",
            ],
            ["translateZ(55px)", "rgba(167,139,250,.15)", "#a78bfa"],
            [
              "rotateY(180deg) translateZ(55px)",
              "rgba(196,181,253,.15)",
              "#c4b5fd",
            ],
            [
              "rotateY(90deg) translateZ(55px)",
              "rgba(124,58,237,.15)",
              "#7c3aed",
            ],
            [
              "rotateY(-90deg) translateZ(55px)",
              "rgba(109,40,217,.15)",
              "#6d28d9",
            ],
          ].map(([t, bg, bc], k) => (
            <F key={k} t={t} bg={bg} bc={bc} />
          ))}
        </div>
        <div style={i}>
          {[
            [
              "rotateX(90deg) translateZ(30px)",
              "rgba(6,182,212,.15)",
              "#06b6d4",
            ],
            [
              "rotateX(-90deg) translateZ(30px)",
              "rgba(14,165,233,.15)",
              "#0ea5e9",
            ],
            ["translateZ(30px)", "rgba(56,189,248,.15)", "#38bdf8"],
            [
              "rotateY(180deg) translateZ(30px)",
              "rgba(125,211,252,.15)",
              "#7dd3fc",
            ],
            [
              "rotateY(90deg) translateZ(30px)",
              "rgba(2,132,199,.15)",
              "#0284c7",
            ],
            [
              "rotateY(-90deg) translateZ(30px)",
              "rgba(3,105,161,.15)",
              "#0369a1",
            ],
          ].map(([t, bg, bc], k) => (
            <F key={k} t={t} bg={bg} bc={bc} w={60} h={60} l={0} tp={0} />
          ))}
