      const arm = i % 4,
        dist = Math.random() * 180 + 10,
        sp = (Math.random() - 0.5) * 0.8;
      return {
        dist,
        angle: (arm * Math.PI) / 2 + dist * 0.07 + sp,
        size: Math.random() * 2 + 0.5,
        hue: 180 + Math.random() * 150,
        ph: Math.random() * Math.PI * 2,
        speed: 0.0008 + Math.random() * 0.0015,
      };
    });
    let id,
      t = 0;
    const draw = () => {
      ctx.fillStyle = "rgba(3,7,18,.25)";
      ctx.fillRect(0, 0, cv.width, cv.height);
      const [cx, cy] = [cv.width / 2, cv.height / 2];
      ctx.beginPath();
      ctx.arc(cx, cy, 12, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(251,191,36,.9)";
      ctx.fill();
      stars.forEach((s) => {
        const a = s.angle + t * s.speed,
          x = cx + s.dist * Math.cos(a),
          y = cy + s.dist * Math.sin(a) * 0.38;
        ctx.beginPath();
        ctx.arc(x, y, s.size, 0, Math.PI * 2);
        ctx.fillStyle =
          "hsla(" +
          s.hue +
          ",80%,75%," +
          (0.4 + 0.6 * Math.sin(t * 0.03 + s.ph)) +
          ")";
        ctx.fill();
      });
      t++;
      id = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(id);
  }, []);
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        minHeight: "100vh",
        background: "#030712",
        gap: 16,
      }}
    >
      <canvas ref={ref} width={500} height={420} style={{ borderRadius: 12 }} />
      <p
        style={{
          color: "#818cf8",
          fontWeight: 700,
