const Matrice3D = () => {
  const ref = React.useRef(null);
  React.useEffect(() => {
    const cv = ref.current;
    if (!cv) return;
    const ctx = cv.getContext("2d");
    const pts = [...Array(8)].flatMap((_, i) =>
      [...Array(8)].map((_, j) => ({ gx: i - 3.5, gy: j - 3.5 })),
    );
    let id,
      t = 0,
      mx = 0,
      my = 0;
    cv.onmousemove = (e) => {
      const r = cv.getBoundingClientRect();
      mx = ((e.clientX - r.left) / cv.width) * 2 - 1;
      my = ((e.clientY - r.top) / cv.height) * 2 - 1;
    };
    const draw = () => {
      ctx.fillStyle = "#0f172a";
      ctx.fillRect(0, 0, cv.width, cv.height);
      const rY = t * 0.012 + mx * 1.2,
        rX = Math.sin(t * 0.007) * 0.4 + my * 0.6,
        cx = cv.width / 2,
        cy = cv.height / 2;
      pts.forEach(({ gx, gy }) => {
        const gz =
          Math.sin(gx * 0.7 + t * 0.04) * Math.cos(gy * 0.7 + t * 0.035) * 2;
        const x1 = gx * Math.cos(rY) - gz * Math.sin(rY),
          z1 = gx * Math.sin(rY) + gz * Math.cos(rY);
        const y1 = gy * Math.cos(rX) - z1 * Math.sin(rX),
          z2 = gy * Math.sin(rX) + z1 * Math.cos(rX);
        const sc = 28,
          p = 600 / (600 + z2 * sc);
        ctx.beginPath();
        ctx.arc(cx + x1 * sc * p, cy + y1 * sc * p, 3.5 * p, 0, Math.PI * 2);
        ctx.fillStyle =
          "rgba(74,222,128," + (0.3 + Math.max(0, (gz + 2) / 4) * 0.7) + ")";
        ctx.fill();
      });
      t++;
      id = requestAnimationFrame(draw);
    };
    draw();
    return () => {
      cancelAnimationFrame(id);
      cv.onmousemove = null;
    };
  }, []);
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        minHeight: "100vh",
        background: "#0f172a",
        gap: 16,
      }}
    >
      <canvas
        ref={ref}
        width={500}
        height={400}
        style={{ borderRadius: 12, cursor: "crosshair" }}
      />
      <p
        style={{
          color: "#4ade80",
          fontWeight: 700,
          letterSpacing: 3,
          fontSize: 13,
          textShadow: "0 0 10px #4ade80",
        }}
      >
        💠 MATRICE 3D INTERACTIVE 💠
      </p>
    </div>
  );
};

