const QuantumWeaver = () => {
  const ref = React.useRef(null);
  React.useEffect(() => {
    const cv = ref.current;
    const ctx = cv.getContext("2d");
    let id,
      t = 0;
    const d = () => {
      ctx.fillStyle = "rgba(10,10,25,.15)";
      ctx.fillRect(0, 0, cv.width, cv.height);
      const cx = cv.width / 2,
        cy = cv.height / 2;
      for (let i = 0; i < 60; i++) {
        const a = t * 0.01 + i * 0.2,
          r = 100 + Math.sin(t * 0.02 + i * 0.5) * 50;
        const x = cx + Math.cos(a) * r,
          y = cy + Math.sin(a * 1.5) * r;
        ctx.beginPath();
        ctx.arc(x, y, 2, 0, Math.PI * 2);
        ctx.fillStyle = i % 2 ? "#a78bfa" : "#6366f1";
        ctx.fill();
        if (i > 0) {
          ctx.beginPath();
          ctx.moveTo(x, y);
          const la = t * 0.01 + (i - 1) * 0.2,
            lr = 100 + Math.sin(t * 0.02 + (i - 1) * 0.5) * 50;
          ctx.lineTo(cx + Math.cos(la) * lr, cy + Math.sin(la * 1.5) * lr);
          ctx.strokeStyle = "rgba(167,139,250,.2)";
          ctx.stroke();
        }
      }
      t++;
      id = requestAnimationFrame(d);
    };
    id = requestAnimationFrame(d);
    return () => cancelAnimationFrame(id);
  }, []);
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
