const NeuralWeb = () => {
  const ref = React.useRef(null);
  React.useEffect(() => {
    const cv = ref.current;
    const ctx = cv.getContext("2d");
    let id,
      t = 0;
    const nodes = [...Array(40)].map(() => ({
      x: Math.random() * cv.width,
      y: Math.random() * cv.height,
      vx: (Math.random() - 0.5) * 2,
      vy: (Math.random() - 0.5) * 2,
    }));
    const d = () => {
      ctx.fillStyle = "#0f172a";
      ctx.fillRect(0, 0, cv.width, cv.height);
      nodes.forEach((n) => {
        n.x += n.vx;
        n.y += n.vy;
        if (n.x < 0 || n.x > cv.width) n.vx *= -1;
        if (n.y < 0 || n.y > cv.height) n.vy *= -1;
        ctx.fillStyle = "#06b6d4";
        ctx.beginPath();
        ctx.arc(n.x, n.y, 2, 0, Math.PI * 2);
        ctx.fill();
        nodes.forEach((m) => {
          const dist = Math.hypot(n.x - m.x, n.y - m.y);
          if (dist < 100) {
            ctx.strokeStyle = "rgba(6,182,212," + (1 - dist / 100) + ")";
            ctx.beginPath();
            ctx.moveTo(n.x, n.y);
            ctx.lineTo(m.x, m.y);
            ctx.stroke();
          }
        });
      });
      t++;
      id = requestAnimationFrame(d);
    };
    id = requestAnimationFrame(d);
    return () => cancelAnimationFrame(id);
  }, []);
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        minHeight: "100vh",
        background: "#0f172a",
      }}
    >
      <canvas ref={ref} width={600} height={500} />
      <p
        style={{
          color: "#06b6d4",
          fontWeight: 800,
          letterSpacing: 4,
          marginTop: -60,
          fontSize: 15,
          textShadow: "0 0 10px #06b6d4",
        }}
      >
        🧠 NEURAL WEB 🧠
      </p>
    </div>
  );
};
